import { PetStoreAPI } from '@petstoreapi/sdk';

const client = new PetStoreAPI({
  accessToken: process.env.OAUTH_ACCESS_TOKEN
});

const newPet = await client.pets.create({
  species: 'dog',
  name: 'Buddy',
  breed: 'Golden Retriever',
  ageMonths: 24,
  size: 'large',
  color: 'Golden',
  gender: 'male',
  goodWithKids: true,

  price: '150.00',
  description: 'Friendly golden retriever looking for an active family'
});

console.log(`Created pet with ID: ${newPet.id}`);

const response = await fetch(
  'https://api.petstoreapi.com/v1/pets',
  {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${accessToken}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      species: 'dog',
      name: 'Buddy',
      breed: 'Golden Retriever',
      ageMonths: 24,
      size: 'large',
      color: 'Golden',
      gender: 'male',
      goodWithKids: true,

      price: '150.00',
      description: 'Friendly golden retriever looking for an active family'
    })
  }
);

const newPet = await response.json();
console.log(`Created pet with ID: ${newPet.id}`);

import { PetStoreAPI } from '@petstoreapi/sdk';

const client = new PetStoreAPI({
  apiKey: process.env.PETSTORE_API_KEY
});

const pet = await client.pets.get('01936c8f-1234-7000-8000-111111111111');
console.log(`Found ${pet.name}, a ${pet.ageMonths}-month-old ${pet.species}`);

const response = await fetch(
  'https://api.petstoreapi.com/v1/pets/01936c8f-1234-7000-8000-111111111111',
  {
    headers: {
      'Accept': 'application/json'
    }
  }
);

const pet = await response.json();
console.log(`Found ${pet.name}, a ${pet.age_months}-month-old ${pet.species}`);

