import { PetStoreAPI } from '@petstoreapi/sdk';

const client = new PetStoreAPI({
  accessToken: process.env.OAUTH_ACCESS_TOKEN
});

const completion = await client.chat.completions.create({
  messages: [
    { role: 'user', content: 'My dog has been scratching a lot lately. What could be causing this?' }
  ],
  model: 'pet-advisor-1',
  stream: false
});

console.log(completion.choices[0].message.content);

import { PetStoreAPI } from '@petstoreapi/sdk';

const client = new PetStoreAPI({
  accessToken: process.env.OAUTH_ACCESS_TOKEN
});

const stream = await client.chat.completions.create({
  messages: [
    { role: 'user', content: 'What\'s the best diet for a senior cat with kidney issues?' }
  ],
  model: 'pet-advisor-1',
  stream: true
});

for await (const chunk of stream) {
  const content = chunk.choices[0]?.delta?.content;
  if (content) {
    process.stdout.write(content);
  }
}

from petstore import PetStoreAPI

client = PetStoreAPI(access_token=os.environ['OAUTH_ACCESS_TOKEN'])

stream = client.chat.completions.create(
    messages=[
        {"role": "user", "content": "My puppy keeps biting furniture. How can I stop this behavior?"}
    ],
    model="pet-advisor-1",
    stream=True
)

for chunk in stream:
    if chunk.choices[0].delta.content:
        print(chunk.choices[0].delta.content, end="")

const response = await fetch(
  'https://api.petstoreapi.com/v1/chat/completions',
  {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${accessToken}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      messages: [
        { role: 'user', content: 'How often should I take my cat to the vet for checkups?' }
      ],
      model: 'pet-advisor-1',
      stream: true
    })
  }
);

const reader = response.body.getReader();
const decoder = new TextDecoder();

while (true) {
  const { value, done } = await reader.read();
  if (done) break;

  const chunk = decoder.decode(value);
  const lines = chunk.split('\n').filter(line => line.startsWith('data: '));

  for (const line of lines) {
    const data = line.replace('data: ', '');
    if (data === '[DONE]') break;
    const parsed = JSON.parse(data);
    process.stdout.write(parsed.choices[0]?.delta?.content || '');
  }
}

