import { PetStoreAPI } from '@petstoreapi/sdk';

const client = new PetStoreAPI({
  accessToken: process.env.OAUTH_ACCESS_TOKEN
});

const inventory = await client.store.getInventory();
console.log(`Available: ${inventory.available}`);
console.log(`Pending: ${inventory.pending}`);
console.log(`Adopted: ${inventory.adopted}`);

const response = await fetch(
  'https://api.petstoreapi.com/v1/inventory',
  {
    headers: {
      'Authorization': `Bearer ${accessToken}`
    }
  }
);

const inventory = await response.json();
console.log(`Available: ${inventory.available}`);
console.log(`Pending: ${inventory.pending}`);
console.log(`Adopted: ${inventory.adopted}`);

